#include <stdio.h>
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N;
        scanf("%d", &N);
        long long A[N];
        for (int i = 0; i < N; i++) {
            scanf("%lld", &A[i]);
        }
        int C, D, S;
        scanf("%d %d %d", &C, &D, &S);
        long long time = 0;
        for (int i = 0; i < N; i++) {
            time += A[i] * C;
        }
        time -= A[N - 1];
        double delay = (double)time / S;
        printf("%.6f\n", delay);
    }
    return 0;
}

