import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int N = sc.nextInt();
            long[] A = new long[N];
            for (int i = 0; i < N; i++) {
                A[i] = sc.nextLong();
            }
            int C = sc.nextInt();
            int D = sc.nextInt();
            int S = sc.nextInt();
            long time = 0;
            for (int i = 0; i < N; i++) {
                time += A[i] * C;
            }
            time -= A[N - 1];
            double delay = (double)time / S;
            System.out.printf("%.6f\n", delay);
        }
    }
}

